from flask import Flask, request, jsonify
import psycopg2
import psycopg2.extras
import re
import os

app = Flask(__name__)

DB_CONFIG = {
    "host": os.getenv("DB_HOST", "localhost"),
    "port": os.getenv("DB_PORT", "5432"),
    "dbname": os.getenv("DB_NAME", "postgres"),
    "user": os.getenv("DB_USER", "postgres"),
    "password": os.getenv("DB_PASSWORD", "postgres"),
}

IDENTIFIER_RE = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")

ALLOWED_OPERATORS = {
    "=": "=",
    "!=": "<>",
    "<>": "<>",
    ">": ">",
    ">=": ">=",
    "<": "<",
    "<=": "<=",
    "like": "LIKE",
    "ilike": "ILIKE",
    "in": "IN",
    "not in": "NOT IN",
    "is": "IS",
    "is not": "IS NOT",
}


def get_conn():
    return psycopg2.connect(**DB_CONFIG)


def validate_identifier(name):
    if not isinstance(name, str) or not IDENTIFIER_RE.match(name):
        raise ValueError(f"Invalid identifier: {name}")
    return name


def validate_identifiers(items):
    return [validate_identifier(item) for item in items]


def build_where_clause(filters):
    if not filters:
        return "", []

    clauses = []
    params = []

    for f in filters:
        if not isinstance(f, dict):
            raise ValueError("Each filter must be an object")

        column = validate_identifier(f.get("column"))
        operator = str(f.get("operator", "=")).strip().lower()
        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Unsupported operator: {operator}")

        sql_operator = ALLOWED_OPERATORS[operator]
        value = f.get("value")

        if operator in {"in", "not in"}:
            if not isinstance(value, (list, tuple)) or len(value) == 0:
                raise ValueError(f"Operator '{operator}' requires a non-empty list value")
            placeholders = ", ".join(["%s"] * len(value))
            clauses.append(f"{column} {sql_operator} ({placeholders})")
            params.extend(value)
        elif operator in {"is", "is not"}:
            if value is not None and str(value).lower() not in {"null", "true", "false"}:
                raise ValueError(f"Operator '{operator}' supports NULL/TRUE/FALSE only")
            if value is None or str(value).lower() == "null":
                clauses.append(f"{column} {sql_operator} NULL")
            else:
                clauses.append(f"{column} {sql_operator} %s")
                params.append(value)
        else:
            clauses.append(f"{column} {sql_operator} %s")
            params.append(value)

    return " WHERE " + " AND ".join(clauses), params


@app.route("/query", methods=["POST"])
def query():
    try:
        payload = request.get_json(force=True)

        table = validate_identifier(payload.get("table"))
        columns = payload.get("columns", ["*"])
        filters = payload.get("filters", [])
        limit = payload.get("limit", 100)
        offset = payload.get("offset", 0)
        order_by = payload.get("order_by", [])

        if columns == ["*"]:
            select_clause = "*"
        else:
            if not isinstance(columns, list) or len(columns) == 0:
                raise ValueError("columns must be a non-empty list or ['*']")
            select_clause = ", ".join(validate_identifiers(columns))

        sql = f"SELECT {select_clause} FROM {table}"
        params = []

        where_clause, where_params = build_where_clause(filters)
        sql += where_clause
        params.extend(where_params)

        if order_by:
            if not isinstance(order_by, list):
                raise ValueError("order_by must be a list")
            order_parts = []
            for item in order_by:
                if isinstance(item, str):
                    col = validate_identifier(item)
                    direction = "ASC"
                elif isinstance(item, dict):
                    col = validate_identifier(item.get("column"))
                    direction = str(item.get("direction", "ASC")).upper()
                    if direction not in {"ASC", "DESC"}:
                        raise ValueError("order_by direction must be ASC or DESC")
                else:
                    raise ValueError("Invalid order_by item")
                order_parts.append(f"{col} {direction}")
            sql += " ORDER BY " + ", ".join(order_parts)

        if limit is not None:
            limit = int(limit)
            if limit < 0:
                raise ValueError("limit must be >= 0")
            sql += " LIMIT %s"
            params.append(limit)

        if offset is not None:
            offset = int(offset)
            if offset < 0:
                raise ValueError("offset must be >= 0")
            sql += " OFFSET %s"
            params.append(offset)

        with get_conn() as conn:
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(sql, params)
                rows = cur.fetchall()

        return jsonify({
            "success": True,
            "count": len(rows),
            "data": rows,
        }), 200

    except (ValueError, KeyError, TypeError) as e:
        return jsonify({"success": False, "error": str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({"success": False, "error": "Database error", "details": str(e)}), 500
    except Exception as e:
        return jsonify({"success": False, "error": "Internal server error", "details": str(e)}), 500


@app.route("/health", methods=["GET"])
def health():
    try:
        with get_conn() as conn:
            with conn.cursor() as cur:
                cur.execute("SELECT 1")
                cur.fetchone()
        return jsonify({"success": True, "status": "ok"}), 200
    except Exception as e:
        return jsonify({"success": False, "status": "error", "details": str(e)}), 500


